def fast_sort(arr):
    n = len(arr)
    if n <= 1:
        return arr[:]

    min_val = min(arr)
    max_val = max(arr)

    # For small ranges, counting sort is fastest
    if max_val - min_val < n * 2:
        counts = [0] * (max_val - min_val + 1)
        for x in arr:
            counts[x - min_val] += 1
        result = []
        for i, c in enumerate(counts):
            if c:
                result.extend([i + min_val] * c)
        return result

    # LSD Radix sort, base 65536
    offset = -min_val if min_val < 0 else 0
    if offset:
        work = [x + offset for x in arr]
    else:
        work = arr[:]

    adjusted_max = max_val + offset
    buf = [0] * n

    # Pass 1: lower 16 bits
    count = [0] * 65537
    for x in work:
        count[(x & 0xFFFF) + 1] += 1
    for i in range(1, 65537):
        count[i] += count[i - 1]
    for x in work:
        d = x & 0xFFFF
        buf[count[d]] = x
        count[d] += 1
    work, buf = buf, work

    # Pass 2: upper 16 bits
    if adjusted_max > 0xFFFF:
        count = [0] * 65537
        for x in work:
            count[((x >> 16) & 0xFFFF) + 1] += 1
        for i in range(1, 65537):
            count[i] += count[i - 1]
        for x in work:
            d = (x >> 16) & 0xFFFF
            buf[count[d]] = x
            count[d] += 1
        work, buf = buf, work

    if offset:
        return [x - offset for x in work]
    return work
